class Solution:
    def waysToBuildRooms(self, prevRoom):
        MOD = 10 ** 9 + 7
        n = len(prevRoom)
        children = [[] for _ in range(n)]
        for i in range(1, n):
            children[prevRoom[i]].append(i)
        size = [1] * n
        order = []
        st = [(0, False)]
        while st:
            node, processed = st.pop()
            if processed:
                order.append(node)
                continue
            st.append((node, True))
            for c in children[node]:
                st.append((c, False))
        for node in order:
            for c in children[node]:
                size[node] += size[c]
        # independent check: exact integer multinomial (n-1)! / prod_{v != root} size[v]
        from math import factorial
        num = factorial(n - 1)
        den = 1
        for v in range(1, n):
            den *= size[v]
        return (num // den) % MOD

