            if processed:
                order.append(node)
                continue
            st.append((node, True))
            for c in children[node]:
                st.append((c, False))
        for node in order:
            for c in children[node]:
                size[node] += size[c]
        maxn = n + 1
        fact = [1] * maxn
        for i in range(1, maxn):
            fact[i] = fact[i - 1] * i % MOD
        inv_fact = [1] * maxn
        inv_fact[maxn - 1] = pow(fact[maxn - 1], MOD - 2, MOD)
        for i in range(maxn - 2, -1, -1):
            inv_fact[i] = inv_fact[i + 1] * (i + 1) % MOD
        res = [1] * n
        for node in order:
            r = fact[size[node] - 1]
            for c in children[node]:
                r = r * res[c] % MOD
                r = r * inv_fact[size[c]] % MOD
            res[node] = r
        return res[0]

