var waysToBuildRooms = function(prevRoom) {
    const MOD = 1000000007n;
    const n = prevRoom.length;
    const children = Array.from({length: n}, () => []);
    for (let i = 1; i < n; i++) children[prevRoom[i]].push(i);
    const size = new Array(n).fill(1);
    const order = [];
    const st = [[0, false]];
    while (st.length) {
        const top = st.pop();
        const node = top[0], processed = top[1];
        if (processed) { order.push(node); continue; }
        st.push([node, true]);
        for (const c of children[node]) st.push([c, false]);
    }
    for (const node of order) for (const c of children[node]) size[node] += size[c];
    const maxn = n + 1;
    const fact = new Array(maxn).fill(1n);
    for (let i = 1; i < maxn; i++) fact[i] = fact[i - 1] * BigInt(i) % MOD;
    const power = (b, e) => { let r = 1n; b %= MOD; while (e > 0n) { if (e & 1n) r = r * b % MOD; b = b * b % MOD; e >>= 1n; } return r; };
    const invFact = new Array(maxn).fill(1n);
    invFact[maxn - 1] = power(fact[maxn - 1], MOD - 2n);
    for (let i = maxn - 2; i >= 0; i--) invFact[i] = invFact[i + 1] * BigInt(i + 1) % MOD;
    const res = new Array(n).fill(1n);
    for (const node of order) {
        let r = fact[size[node] - 1];
        for (const c of children[node]) {
            r = r * res[c] % MOD;
            r = r * invFact[size[c]] % MOD;
        }
        res[node] = r;
    }
    return Number(res[0]);
};
